1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function getItemBasePremium(item: any): number {
18	  return BASE_PREMIUM[item.type] ?? 0;
19	}
20	
21	function countByType(items: any[]): Record<string, number> {
22	  const counts: Record<string, number> = {};
23	  for (const item of items) {
24	    counts[item.type] = (counts[item.type] ?? 0) + 1;
25	  }
26	  return counts;
27	}
28	
29	function calculateBasePremium(typeCounts: Record<string, number>): number {
30	  let total = 0;
31	  for (const [type, count] of Object.entries(typeCounts)) {
32	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
33	      total += BLOCK_PREMIUM;
34	    } else {
35	      total += count * (BASE_PREMIUM[type] ?? 0);
36	    }
37	  }
38	  return total;
39	}
40	
41	const CURSED_SURCHARGE_RATE = 0.5;
42	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const ENCHANTMENT_THRESHOLD = 5;
44	
45	function calculateItemSurcharges(items: any[]): number {
46	  let total = 0;
47	  for (const item of items) {
48	    const base = getItemBasePremium(item);
49	    if (item.cursed) {
50	      total += base * CURSED_SURCHARGE_RATE;
51	    }
52	    if ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD) {
53	      total += base * ENCHANTMENT_SURCHARGE_RATE;
54	    }
55	  }
56	  return total;
57	}
58	
59	function calculateQuotePremium(items: any[]): number {
60	  const typeCounts = countByType(items);
61	  const basePremium = calculateBasePremium(typeCounts);
62	  const itemSurcharges = calculateItemSurcharges(items);
63	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
64	  return Math.ceil(basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE);
65	}
66	
67	export function processScenario(scenario: any): unknown {
68	  const results = scenario.steps.map((step: any) => ({
69	    premium: calculateQuotePremium(step.items),
70	  }));
71	
72	  return { results };
73	}
